// ============================================================
// PROTEIN PLANNER STATE ENGINE v1
// Replaces Agent 2 (meal planning) + Agent 3 (weekly order)
// Pure deterministic logic - no Claude needed for standard flow
// ============================================================

const webhook = $('Webhook').item.json.body;
const userData = $('Get User & Products').item.json;
const rawMessage = webhook.message || '';
const userMessage = (typeof rawMessage === 'string' ? rawMessage : JSON.stringify(rawMessage)).trim().toLowerCase();
const products = userData.products || [];
const history = userData.conversation_history || [];

// Parse existing state from context or initialize
let state;
try {
  state = (typeof userData.context === 'string') ? JSON.parse(userData.context) : (userData.context || null);
} catch(e) { state = null; }

if (!state || !state.engine_version) {
  state = {
    engine_version: 1,
    step: 'budget_setup',
    sub_step: 'init',
    supplement_g: userData.supplement_protein_g || 0,
    original_protein: userData.daily_protein_g || 0,
    protein_target: (userData.daily_protein_g || 0) - (userData.supplement_protein_g || 0),
    meals_per_day: userData.meals_per_day || 3,
    distribution: null,
    distribution_label: null,
    meals: [],
    current_meal: 0,
    carried_portions: {},
    running_price: 0,
    weekly_plan: null,
    cart: null,
    stage_complete: false
  };
}

// ============================================================
// HELPER FUNCTIONS
// ============================================================

function roundTo5(n) { return Math.round(n / 5) * 5; }

function getProductsByCategory(cat) {
  return products.filter(p => p.category && p.category.toLowerCase() === cat.toLowerCase());
}

function getProductsByCut(cat, cut) {
  return products.filter(p => {
    const pCat = (p.category || '').toLowerCase();
    const pCut = (p.cut_type || '').toLowerCase();
    return pCat === cat.toLowerCase() && pCut === cut.toLowerCase();
  });
}

function findProduct(name) {
  return products.find(p => p.product_name.toLowerCase() === name.toLowerCase());
}

function calcDistribution(target, label) {
  const t = target;
  if (label === 'Equal') {
    const base = Math.floor(t / 3);
    return { breakfast: base, lunch: base, dinner: t - (base * 2) };
  }
  if (label === 'Heavy Breakfast') {
    return { breakfast: Math.round(t * 0.4), lunch: Math.round(t * 0.3), dinner: t - Math.round(t * 0.4) - Math.round(t * 0.3) };
  }
  if (label === 'Heavy Lunch') {
    return { breakfast: Math.round(t * 0.3), lunch: Math.round(t * 0.4), dinner: t - Math.round(t * 0.3) - Math.round(t * 0.4) };
  }
  if (label === 'Heavy Dinner') {
    return { breakfast: Math.round(t * 0.3), lunch: Math.round(t * 0.3), dinner: t - Math.round(t * 0.3) - Math.round(t * 0.3) };
  }
  // Default equal
  const base = Math.floor(t / 3);
  return { breakfast: base, lunch: base, dinner: t - (base * 2) };
}

function getCutTypes(category) {
  const cutMap = {
    'chicken': ['Boneless', 'Curry Cut', 'Keema', 'Leg & Thigh'],
    'fish': ['Boneless Cubes', 'Steaks & Cut', 'Whole', 'Fillet', 'Others'],
    'mutton': ['Curry Cut', 'Mince', 'Mini Pack']
  };
  return cutMap[category.toLowerCase()] || [];
}

function calcPortionForProduct(prod, proteinNeeded) {
  const cat = (prod.category || '').toLowerCase();
  if (cat === 'eggs') {
    const eggsNeeded = Math.ceil(proteinNeeded / 6.5);
    // Derive egg count from pack_size_label like "Pack of 6" or "Pack of 10"
    const labelMatch = (prod.pack_size_label || '').match(/(\d+)/);
    const eggCount = labelMatch ? parseInt(labelMatch[1]) : 6;
    return {
      quantity: eggsNeeded,
      unit: 'eggs',
      portion_grams: eggsNeeded * 50,
      protein_g: Math.round(eggsNeeded * 6.5 * 10) / 10,
      pack_size: eggCount,
      pack_price: prod.price
    };
  } else {
    const per100 = prod.protein_per_100g || 20;
    let grams = roundTo5((proteinNeeded / per100) * 100);
    if (grams < 50) grams = 50;
    const actualProtein = Math.round((grams * per100 / 100) * 10) / 10;
    return {
      quantity: grams,
      unit: 'g',
      portion_grams: grams,
      protein_g: actualProtein,
      pack_size: prod.pack_size_grams || 450,
      pack_price: prod.price
    };
  }
}

function buildUtilizationOptions(prod, portion, isLastMeal) {
  const cat = (prod.category || '').toLowerCase();
  const options = [];
  let remaining, remainingText;

  if (cat === 'eggs') {
    const packSize = portion.pack_size; // egg count, not grams
    const used = portion.quantity;
    remaining = packSize - used;
    if (remaining <= 0) return { remaining: 'Full pack used', options: [] };
    remainingText = remaining + ' eggs remaining from pack of ' + packSize;
    const totalDays = Math.floor(packSize / used);
    if (totalDays >= 2) {
      options.push({ label: 'Same meal for ' + totalDays + ' days (' + used + ' eggs/day)', value: 'same_meal_multi_day', days: totalDays });
    } else if (remaining > 0) {
      options.push({ label: 'Use remaining ' + remaining + ' eggs next day', value: 'same_meal_multi_day', days: 2 });
    }
    if (!isLastMeal) {
      options.push({ label: 'Use ' + remaining + ' eggs for a different meal today', value: 'other_meal' });
    }
  } else {
    const packSize = portion.pack_size;
    const used = portion.portion_grams;
    remaining = packSize - used;
    if (remaining <= 0) return { remaining: 'Full pack used', options: [] };
    remainingText = remaining + 'g remaining from ' + packSize + 'g pack';

    // How many total days does one pack cover?
    const totalDays = Math.floor(packSize / used);
    if (totalDays >= 2) {
      options.push({ label: 'Same meal for ' + totalDays + ' days (' + used + 'g/day)', value: 'same_meal_multi_day', days: totalDays });
    } else if (remaining > 0) {
      // Pack doesn't cover 2 full days but has leftovers — still offer multi-day with adjusted portion
      options.push({ label: 'Use remaining ' + remaining + 'g for next day (lower portion)', value: 'same_meal_multi_day', days: 2 });
    }
    if (!isLastMeal) {
      options.push({ label: 'Use ' + remaining + 'g for a different meal today', value: 'other_meal' });
    }
    // Check if smaller pack exists
    const smallerPacks = products.filter(p => 
      p.product_name !== prod.product_name && 
      (p.category || '').toLowerCase() === cat &&
      (p.cut_type || '').toLowerCase() === (prod.cut_type || '').toLowerCase() &&
      p.pack_size_grams < packSize &&
      p.pack_size_grams >= used
    );
    if (smallerPacks.length > 0) {
      const sp = smallerPacks[0];
      options.push({ label: 'Switch to ' + sp.pack_size_label + ' pack (₹' + sp.price + ')', value: 'smaller_pack', product: sp.product_name });
    }
  }

  return { remaining: remainingText, remaining_amount: remaining, options: options };
}

const mealLabels = ['Breakfast', 'Lunch', 'Dinner'];

// ============================================================
// PARSE USER SELECTION FROM MESSAGE
// ============================================================
function parseSelection(msg) {
  // If already an object (frontend sent JSON object directly), return it
  if (msg && typeof msg === 'object') return msg;

  // If string, try to parse as JSON
  if (typeof msg === 'string') {
    try {
      const parsed = JSON.parse(msg);
      if (parsed && typeof parsed === 'object') return parsed;
    } catch(e) {}
  }

  // Otherwise parse natural language
  return { raw: String(msg || '') };
}

const selection = parseSelection(webhook.message);

// ============================================================
// STATE MACHINE
// ============================================================

let response = null;
let needsClaude = false;
let claudePrompt = '';

// ---- EDIT/GO-BACK HANDLER ----
const editMatch = userMessage.match(/edit\s*(breakfast|lunch|dinner)/i) || 
                  userMessage.match(/change\s*(breakfast|lunch|dinner)/i) ||
                  userMessage.match(/go\s*back\s*to\s*(breakfast|lunch|dinner)/i);
if (editMatch && state.step !== 'budget_setup') {
  const editMeal = editMatch[1].toLowerCase();
  const mealIdx = editMeal === 'breakfast' ? 0 : editMeal === 'lunch' ? 1 : 2;
  if (mealIdx < state.meals.length) {
    // Reset this meal and recalculate running price
    const oldMealProducts = state.meals[mealIdx].products || [];
    for (const p of oldMealProducts) {
      const days = p.days_covered || 1;
      state.running_price -= Math.round((p.pack_price || 0) / days);
    }
    if (state.running_price < 0) state.running_price = 0;

    state.meals[mealIdx] = {
      label: state.meals[mealIdx].label,
      target_g: state.meals[mealIdx].target_g,
      sources: [],
      cuts: {},
      products: [],
      confirmed: false
    };

    // Remove any carried portions FROM this meal
    const mealKey = state.meals[mealIdx].label.toLowerCase();
    delete state.carried_portions[mealKey];

    state.current_meal = mealIdx;
    state.step = 'meal_curation';
    state.sub_step = 'source_select';

    const meal = state.meals[mealIdx];
    const carried = state.carried_portions[mealKey] || [];
    const carriedP = carried.reduce((s, c) => s + c.protein_g, 0);
    const effective = Math.max(0, meal.target_g - carriedP);

    response = makeResponse(
      "Editing " + meal.label + "! Target: " + meal.target_g + "g protein. Choose your protein sources:",
      'source_select',
      {
        meal_label: meal.label,
        protein_target: effective,
        carried_portions: carried,
        available_sources: [
          { name: 'eggs', icon: '🥚' },
          { name: 'chicken', icon: '🍗' },
          { name: 'fish', icon: '🐟' },
          { name: 'mutton', icon: '🍖' }
        ]
      }
    );
  }
}

function makeResponse(message, uiType, uiData, extras) {
  const resp = {
    message: message,
    current_step: state.step,
    ui_type: uiType,
    ui_data: uiData,
    state: state,
    stage_complete: state.stage_complete
  };
  if (extras) Object.assign(resp, extras);
  return resp;
}

// ============================================================
// STEP: budget_setup
// ============================================================
if (state.step === 'budget_setup') {

  if (state.sub_step === 'init') {
    // First message - ask about supplements
    state.sub_step = 'awaiting_supplement';

    response = makeResponse(
      "Let's plan your protein meals! Your daily target is " + state.original_protein + "g protein. Do you take any protein supplements?",
      'supplement_ask',
      {
        original_protein: state.original_protein,
        meals_per_day: state.meals_per_day,
        options: [
          { label: 'No supplements', value: 'none', grams: 0 },
          { label: '25g (1 scoop whey)', value: '25', grams: 25 },
          { label: '30g supplement', value: '30', grams: 30 },
          { label: '50g supplement', value: '50', grams: 50 },
          { label: 'Custom amount', value: 'custom', grams: 0 }
        ]
      }
    );
  }

  else if (state.sub_step === 'awaiting_supplement') {
    let suppGrams = 0;

    if (selection.supplement_grams !== undefined) {
      suppGrams = Number(selection.supplement_grams) || 0;
    } else if (selection.supplement) {
      suppGrams = Number(selection.supplement) || 0;
    } else {
      // Parse from text
      const numMatch = userMessage.match(/(\d+)\s*g/);
      if (numMatch) {
        suppGrams = parseInt(numMatch[1]);
      } else if (userMessage.includes('no') || userMessage.includes('none') || userMessage.includes('0')) {
        suppGrams = 0;
      } else {
        const numOnly = userMessage.match(/(\d+)/);
        if (numOnly) suppGrams = parseInt(numOnly[1]);
      }
    }

    state.supplement_g = suppGrams;
    state.protein_target = state.original_protein - suppGrams;

    // Now show distribution options
    const target = state.protein_target;
    const distributions = [
      { label: 'Equal', icon: '⚖️', values: calcDistribution(target, 'Equal') },
      { label: 'Heavy Breakfast', icon: '🌅', values: calcDistribution(target, 'Heavy Breakfast') },
      { label: 'Heavy Lunch', icon: '☀️', values: calcDistribution(target, 'Heavy Lunch') },
      { label: 'Heavy Dinner', icon: '🌙', values: calcDistribution(target, 'Heavy Dinner') },
    ];

    state.sub_step = 'awaiting_distribution';

    response = makeResponse(
      (suppGrams > 0 ? suppGrams + "g from supplements deducted. " : "No supplements. ") +
      "Protein from food: " + target + "g. How would you like to distribute across " + state.meals_per_day + " meals?",
      'budget_setup',
      {
        protein_target: target,
        supplement_g: state.supplement_g,
        original_protein: state.original_protein,
        meals_per_day: state.meals_per_day,
        distributions: distributions
      }
    );
  }

  else if (state.sub_step === 'awaiting_distribution') {
    // User selected a distribution
    let distLabel = null;

    if (selection.distribution) {
      distLabel = selection.distribution;
    } else {
      const msg = userMessage;
      if (msg.includes('equal')) distLabel = 'Equal';
      else if (msg.includes('heavy breakfast') || msg.includes('breakfast')) distLabel = 'Heavy Breakfast';
      else if (msg.includes('heavy lunch') || msg.includes('lunch')) distLabel = 'Heavy Lunch';
      else if (msg.includes('heavy dinner') || msg.includes('dinner')) distLabel = 'Heavy Dinner';
      else if (msg.includes('custom')) {
        // Custom needs Claude to parse
        needsClaude = true;
        claudePrompt = 'The user wants a custom protein distribution. Their message: "' + webhook.message + '". Their protein target from food is ' + state.protein_target + 'g across ' + state.meals_per_day + ' meals. Parse their desired distribution and respond ONLY with JSON: {"breakfast": number, "lunch": number, "dinner": number}. Numbers must sum to ' + state.protein_target + '.';
        state.sub_step = 'awaiting_custom_distribution';
      }
      else {
        // Default to equal if message looks like confirmation
        if (msg.includes('yes') || msg.includes('confirm') || msg.includes('ok') || msg.includes('looks good')) {
          distLabel = 'Equal';
        } else {
          distLabel = 'Equal'; // fallback
        }
      }
    }

    if (distLabel && !needsClaude) {
      state.distribution = calcDistribution(state.protein_target, distLabel);
      state.distribution_label = distLabel;

      // Initialize meals
      state.meals = [
        { label: 'Breakfast', target_g: state.distribution.breakfast, sources: [], cuts: {}, products: [], confirmed: false },
        { label: 'Lunch', target_g: state.distribution.lunch, sources: [], cuts: {}, products: [], confirmed: false },
        { label: 'Dinner', target_g: state.distribution.dinner, sources: [], cuts: {}, products: [], confirmed: false }
      ];
      state.current_meal = 0;
      state.step = 'meal_curation';
      state.sub_step = 'source_select';

      const meal = state.meals[0];

      // Check for carried portions
      const carried = state.carried_portions[meal.label.toLowerCase()] || [];
      let carriedMsg = '';
      let adjustedTarget = meal.target_g;
      if (carried.length > 0) {
        const carriedProtein = carried.reduce((s, c) => s + c.protein_g, 0);
        adjustedTarget = Math.max(0, meal.target_g - carriedProtein);
        carriedMsg = ' You have ' + Math.round(carriedProtein) + 'g protein carried over. Need ' + adjustedTarget + 'g more.';
      }

      response = makeResponse(
        state.distribution_label + " distribution confirmed! " + meal.label + " target: " + meal.target_g + "g protein." + carriedMsg + " Choose your protein sources:",
        'source_select',
        {
          meal_label: meal.label,
          protein_target: adjustedTarget,
          carried_portions: carried,
          available_sources: [
            { name: 'eggs', icon: '🥚' },
            { name: 'chicken', icon: '🍗' },
            { name: 'fish', icon: '🐟' },
            { name: 'mutton', icon: '🍖' }
          ]
        }
      );
    }
  }

  else if (state.sub_step === 'awaiting_custom_distribution') {
    // Claude returned custom distribution
    try {
      const parsed = JSON.parse(webhook.message);
      state.distribution = parsed;
      state.distribution_label = 'Custom';
      state.meals = [
        { label: 'Breakfast', target_g: parsed.breakfast, sources: [], cuts: {}, products: [], confirmed: false },
        { label: 'Lunch', target_g: parsed.lunch, sources: [], cuts: {}, products: [], confirmed: false },
        { label: 'Dinner', target_g: parsed.dinner, sources: [], cuts: {}, products: [], confirmed: false }
      ];
      state.current_meal = 0;
      state.step = 'meal_curation';
      state.sub_step = 'source_select';

      response = makeResponse(
        "Custom distribution set! Breakfast: " + parsed.breakfast + "g, Lunch: " + parsed.lunch + "g, Dinner: " + parsed.dinner + "g. Choose protein sources for Breakfast:",
        'source_select',
        {
          meal_label: 'Breakfast',
          protein_target: parsed.breakfast,
          available_sources: [
            { name: 'eggs', icon: '🥚' },
            { name: 'chicken', icon: '🍗' },
            { name: 'fish', icon: '🐟' },
            { name: 'mutton', icon: '🍖' }
          ]
        }
      );
    } catch(e) {
      // Parse failed, ask again
      response = makeResponse("I couldn't understand that distribution. Please choose: Equal, Heavy Breakfast, Heavy Lunch, or Heavy Dinner.", 'budget_setup', {
        protein_target: state.protein_target,
        supplement_g: state.supplement_g,
        original_protein: state.original_protein,
        meals_per_day: state.meals_per_day,
        distributions: [
          { label: 'Equal', icon: '⚖️', values: calcDistribution(state.protein_target, 'Equal') },
          { label: 'Heavy Breakfast', icon: '🌅', values: calcDistribution(state.protein_target, 'Heavy Breakfast') },
          { label: 'Heavy Lunch', icon: '☀️', values: calcDistribution(state.protein_target, 'Heavy Lunch') },
          { label: 'Heavy Dinner', icon: '🌙', values: calcDistribution(state.protein_target, 'Heavy Dinner') },
        ]
      });
    }
  }
}

// ============================================================
// STEP: meal_curation
// ============================================================
else if (state.step === 'meal_curation') {
  const meal = state.meals[state.current_meal];
  const mealKey = meal.label.toLowerCase();

  // Calculate effective target considering carried portions
  const carried = state.carried_portions[mealKey] || [];
  const carriedProtein = carried.reduce((s, c) => s + c.protein_g, 0);
  const effectiveTarget = Math.max(0, meal.target_g - carriedProtein);

  // ---- SOURCE SELECT ----
  if (state.sub_step === 'source_select') {
    let sources = [];

    if (selection.sources && Array.isArray(selection.sources)) {
      sources = selection.sources;
    } else {
      // Parse from text
      const msg = userMessage;
      if (msg.includes('egg')) sources.push('eggs');
      if (msg.includes('chicken')) sources.push('chicken');
      if (msg.includes('fish')) sources.push('fish');
      if (msg.includes('mutton') || msg.includes('lamb') || msg.includes('goat')) sources.push('mutton');
    }

    if (sources.length === 0) {
      response = makeResponse(
        "Please select at least one protein source for " + meal.label + ":",
        'source_select',
        {
          meal_label: meal.label,
          protein_target: effectiveTarget,
          carried_portions: carried,
          available_sources: [
            { name: 'eggs', icon: '🥚' },
            { name: 'chicken', icon: '🍗' },
            { name: 'fish', icon: '🐟' },
            { name: 'mutton', icon: '🍖' }
          ]
        }
      );
    } else {
      meal.sources = sources.slice(0, 3); // Max 3

      // Check which sources need cut selection
      const needsCut = meal.sources.filter(s => s !== 'eggs');

      if (needsCut.length > 0) {
        // Need to ask cut type for first non-egg source
        state.sub_step = 'cut_select';
        state._pending_cuts = needsCut;
        state._current_cut_source = 0;

        const firstSource = needsCut[0];
        const cuts = getCutTypes(firstSource);

        response = makeResponse(
          "Great! What type of " + firstSource + " do you prefer?",
          'cut_select',
          { category: firstSource, cuts: cuts }
        );
      } else {
        // Only eggs selected - skip to product select
        state.sub_step = 'product_select';
        const eggProducts = getProductsByCategory('eggs').slice(0, 4);

        response = makeResponse(
          "Choose your eggs product for " + meal.label + ":",
          'product_select',
          {
            meal_label: meal.label,
            protein_target: effectiveTarget,
            products: eggProducts.map(p => ({
              product_name: p.product_name,
              pack_size_label: p.pack_size_label,
              price: p.price,
              protein_per_100g: p.protein_per_100g,
              protein_per_pack: p.protein_per_pack,
              image_url: p.image_url || '',
              category: p.category
            }))
          }
        );
      }
    }
  }

  // ---- CUT SELECT ----
  else if (state.sub_step === 'cut_select') {
    const pendingCuts = state._pending_cuts || [];
    const currentIdx = state._current_cut_source || 0;
    const currentSource = pendingCuts[currentIdx];

    let selectedCut = null;
    if (selection.cut) {
      selectedCut = selection.cut;
    } else {
      // Parse from text - match against known cuts
      const cuts = getCutTypes(currentSource);
      for (const cut of cuts) {
        if (userMessage.includes(cut.toLowerCase())) {
          selectedCut = cut;
          break;
        }
      }
      // Fallback: take first word match
      if (!selectedCut) {
        if (userMessage.includes('boneless')) selectedCut = 'Boneless';
        else if (userMessage.includes('curry')) selectedCut = 'Curry Cut';
        else if (userMessage.includes('keema') || userMessage.includes('mince')) selectedCut = currentSource === 'chicken' ? 'Keema' : 'Mince';
        else if (userMessage.includes('leg') || userMessage.includes('thigh')) selectedCut = 'Leg & Thigh';
        else if (userMessage.includes('fillet')) selectedCut = 'Fillet';
        else if (userMessage.includes('steak')) selectedCut = 'Steaks & Cut';
        else if (userMessage.includes('whole')) selectedCut = 'Whole';
        else if (userMessage.includes('prawn')) selectedCut = 'Others';
        else if (userMessage.includes('mini')) selectedCut = 'Mini Pack';
        else if (userMessage.includes('cube')) selectedCut = 'Boneless Cubes';
      }
    }

    if (!selectedCut) {
      const cuts = getCutTypes(currentSource);
      response = makeResponse(
        "Please select a cut type for " + currentSource + ":",
        'cut_select',
        { category: currentSource, cuts: cuts }
      );
    } else {
      meal.cuts[currentSource] = selectedCut;

      // Check if more sources need cut selection
      if (currentIdx + 1 < pendingCuts.length) {
        state._current_cut_source = currentIdx + 1;
        const nextSource = pendingCuts[currentIdx + 1];
        const cuts = getCutTypes(nextSource);
        response = makeResponse(
          selectedCut + " selected! Now what type of " + nextSource + "?",
          'cut_select',
          { category: nextSource, cuts: cuts }
        );
      } else {
        // All cuts selected - show products
        state.sub_step = 'product_select';

        // Gather products per source (up to 4 per source, not per meal)
        let allProducts = [];
        const productsBySource = {};
        for (const src of meal.sources) {
          if (src === 'eggs') {
            const eggProds = getProductsByCategory('eggs').slice(0, 4);
            allProducts = allProducts.concat(eggProds);
            productsBySource[src] = eggProds.map(p => p.product_name);
          } else {
            const cut = meal.cuts[src];
            let cutProds = [];

            // Filter by exact cut_type match
            if (cut) {
              cutProds = getProductsByCut(src, cut);
            }

            // Only if ZERO products match the cut, fall back to all products in category
            if (cutProds.length === 0) {
              cutProds = getProductsByCategory(src);
            }

            const sliced = cutProds.slice(0, 4);
            allProducts = allProducts.concat(sliced);
            productsBySource[src] = sliced.map(p => p.product_name);
          }
        }

        response = makeResponse(
          "Choose 1 product per source for " + meal.label + ". Pick from each category below:",
          'product_select',
          {
            meal_label: meal.label,
            protein_target: effectiveTarget,
            sources_selected: meal.sources,
            products_by_source: productsBySource,
            products: allProducts.map(p => ({
              product_name: p.product_name,
              pack_size_label: p.pack_size_label,
              price: p.price,
              protein_per_100g: p.protein_per_100g,
              protein_per_pack: p.protein_per_pack,
              image_url: p.image_url || '',
              category: p.category,
              cut_type: p.cut_type || ''
            }))
          }
        );
      }
    }
  }

  // ---- PRODUCT SELECT ----
  else if (state.sub_step === 'product_select') {
    let selectedProducts = [];

    if (selection.products && Array.isArray(selection.products)) {
      selectedProducts = selection.products.map(name => findProduct(name)).filter(Boolean);
    } else {
      // Parse product names from text
      for (const p of products) {
        if (userMessage.includes(p.product_name.toLowerCase())) {
          selectedProducts.push(p);
        }
      }
    }

    if (selectedProducts.length === 0) {
      // Show products again
      let allProducts = [];
      for (const src of meal.sources) {
        if (src === 'eggs') {
          allProducts = allProducts.concat(getProductsByCategory('eggs').slice(0, 3));
        } else {
          const cut = meal.cuts[src];
          let cutProds = cut ? getProductsByCut(src, cut) : getProductsByCategory(src);
          allProducts = allProducts.concat(cutProds.slice(0, 4));
        }
      }
      response = makeResponse(
        "Please select products for " + meal.label + ":",
        'product_select',
        {
          meal_label: meal.label,
          protein_target: effectiveTarget,
          products: allProducts.map(p => ({
            product_name: p.product_name,
            pack_size_label: p.pack_size_label,
            price: p.price,
            protein_per_100g: p.protein_per_100g,
            protein_per_pack: p.protein_per_pack,
            image_url: p.image_url || '',
            category: p.category
          }))
        }
      );
    } else {
      // Limit to 1 per source category
      const byCategory = {};
      for (const p of selectedProducts) {
        const cat = (p.category || '').toLowerCase();
        if (!byCategory[cat]) byCategory[cat] = p;
      }
      selectedProducts = Object.values(byCategory);

      // Calculate portions - split protein equally across sources
      const proteinPerSource = effectiveTarget / selectedProducts.length;
      const portions = [];
      const utilOpts = [];
      let totalProtein = 0;
      let totalPrice = 0;

      for (const prod of selectedProducts) {
        const portion = calcPortionForProduct(prod, proteinPerSource);
        totalProtein += portion.protein_g;
        totalPrice += portion.pack_price;

        const cat = (prod.category || '').toLowerCase();
        const isLastMeal = state.current_meal >= (state.meals_per_day - 1);
        const util = buildUtilizationOptions(prod, portion, isLastMeal);

        portions.push({
          product_name: prod.product_name,
          category: prod.category,
          quantity: cat === 'eggs' ? portion.quantity + ' eggs' : portion.portion_grams + 'g',
          protein_g: portion.protein_g,
          pack_info: prod.pack_size_label + ' @ ₹' + prod.price,
          remaining: util.remaining,
          image_url: prod.image_url || '',
          _portion_data: portion
        });

        if (util.options.length > 0) {
          utilOpts.push({
            product_name: prod.product_name,
            remaining: util.remaining,
            remaining_amount: util.remaining_amount,
            options: util.options
          });
        }
      }

      // Auto-adjust if within ±10g
      if (Math.abs(totalProtein - effectiveTarget) <= 10 && Math.abs(totalProtein - effectiveTarget) > 0.5) {
        // Adjust the largest portion
        const diff = effectiveTarget - totalProtein;
        if (portions.length > 0) {
          // Just note the adjustment in message
        }
      }

      // Store products in meal state
      meal.products = portions.map(p => ({
        product_name: p.product_name,
        category: p.category,
        portion_grams: p._portion_data.portion_grams,
        quantity: p._portion_data.quantity,
        unit: p._portion_data.unit,
        protein_g: p.protein_g,
        pack_size: p._portion_data.pack_size,
        pack_price: p._portion_data.pack_price,
        image_url: p.image_url
      }));

      state.sub_step = 'portion_confirm';

      // Clean up _portion_data before sending to frontend
      const cleanPortions = portions.map(p => {
        const { _portion_data, ...clean } = p;
        return clean;
      });

      response = makeResponse(
        meal.label + " portions calculated! Total: " + Math.round(totalProtein * 10) / 10 + "g protein (target: " + effectiveTarget + "g). How would you like to use remaining product?",
        'portion_confirm',
        {
          meal_label: meal.label,
          protein_target: effectiveTarget,
          portions: cleanPortions,
          total_protein: Math.round(totalProtein * 10) / 10,
          price: totalPrice,
          utilization_options: utilOpts
        }
      );
    }
  }

  // ---- PORTION CONFIRM (utilization) ----
  else if (state.sub_step === 'portion_confirm') {
    // Parse utilization choices
    let utilChoices = {};

    if (selection.utilization && typeof selection.utilization === 'object') {
      utilChoices = selection.utilization;
    } else {
      // Parse from text
      const msg = userMessage;
      if (msg.includes('same meal') || msg.includes('multi day') || msg.includes('next day') || msg.includes('option 1') || msg.includes('1')) {
        // Default all to same_meal_multi_day
        for (const p of meal.products) {
          utilChoices[p.product_name] = 'same_meal_multi_day';
        }
      } else if (msg.includes('different meal') || msg.includes('other meal') || msg.includes('option 2') || msg.includes('2')) {
        for (const p of meal.products) {
          utilChoices[p.product_name] = 'other_meal';
        }
      } else if (msg.includes('confirm') || msg.includes('yes') || msg.includes('ok') || msg.includes('looks good')) {
        // Default to same_meal_multi_day
        for (const p of meal.products) {
          utilChoices[p.product_name] = 'same_meal_multi_day';
        }
      }
    }

    // Apply utilization choices
    for (const prod of meal.products) {
      const choice = utilChoices[prod.product_name] || 'same_meal_multi_day';
      prod.pack_utilization = choice;

      const cat = (prod.category || '').toLowerCase();
      const remaining = cat === 'eggs' ? 
        (prod.pack_size - prod.quantity) :
        (prod.pack_size - prod.portion_grams);

      if (choice === 'same_meal_multi_day') {
        const perDay = cat === 'eggs' ? prod.quantity : prod.portion_grams;
        prod.days_covered = perDay > 0 ? Math.floor(prod.pack_size / perDay) : 1;
      } else if (choice === 'other_meal') {
        prod.days_covered = 1;
        // Calculate protein from remaining and carry to next meal
        const per100 = (findProduct(prod.product_name) || {}).protein_per_100g || 20;
        let carriedProtein;
        if (cat === 'eggs') {
          carriedProtein = remaining * 6.5;
        } else {
          carriedProtein = Math.round((remaining * per100 / 100) * 10) / 10;
        }

        // Determine which meal to carry to
        const nextMealIdx = state.current_meal + 1;
        if (nextMealIdx < 3) {
          const nextMealKey = mealLabels[nextMealIdx].toLowerCase();
          if (!state.carried_portions[nextMealKey]) state.carried_portions[nextMealKey] = [];
          state.carried_portions[nextMealKey].push({
            product_name: prod.product_name,
            grams: remaining,
            protein_g: carriedProtein
          });
        }
      }
    }

    // Calculate running price (per-day cost based on pack utilization)
    let mealPrice = 0;
    for (const p of meal.products) {
      const days = p.days_covered || 1;
      // Daily cost = pack price / days the pack covers
      mealPrice += Math.round(p.pack_price / days);
    }
    state.running_price += mealPrice;

    // Confirm meal
    meal.confirmed = true;
    state.sub_step = 'meal_confirmed';

    response = makeResponse(
      meal.label + " locked! Daily cost so far: ₹" + state.running_price,
      'meal_confirmed',
      {
        meal_label: meal.label,
        total_protein: Math.round(meal.products.reduce((s, p) => s + p.protein_g, 0) * 10) / 10,
        running_price_daily: state.running_price,
        running_price_weekly: state.running_price * 7,
        products: meal.products.map(p => p.product_name),
        days_covered: meal.products.map(p => ({ product_name: p.product_name, days: p.days_covered || 1 }))
      }
    );

    // Move to next meal or consolidation
    if (state.current_meal < state.meals_per_day - 1) {
      state.current_meal += 1;
      state.sub_step = 'source_select';

      const nextMeal = state.meals[state.current_meal];
      const nextCarried = state.carried_portions[nextMeal.label.toLowerCase()] || [];
      const nextCarriedProtein = nextCarried.reduce((s, c) => s + c.protein_g, 0);
      const nextEffective = Math.max(0, nextMeal.target_g - nextCarriedProtein);

      let carriedMsg = '';
      if (nextCarried.length > 0) {
        carriedMsg = ' You have ' + Math.round(nextCarriedProtein) + 'g carried over from leftover packs.';
        if (nextEffective <= 0) {
          carriedMsg += ' Your ' + nextMeal.label + ' protein is already covered!';
        } else {
          carriedMsg += ' Need ' + nextEffective + 'g more.';
        }
      }

      // Append next meal prompt to response
      response.message += " Moving to " + nextMeal.label + " (" + nextMeal.target_g + "g target)." + carriedMsg;

      if (nextEffective <= 0) {
        // Meal is covered by carried portions
        nextMeal.confirmed = true;
        nextMeal.products = nextCarried.map(c => ({
          product_name: c.product_name,
          protein_g: c.protein_g,
          portion_grams: c.grams,
          pack_price: 0,
          pack_utilization: 'carried_over'
        }));

        // Check if all meals done
        if (state.current_meal >= state.meals_per_day - 1 || state.meals.every(m => m.confirmed)) {
          state.step = 'consolidation';
          state.sub_step = 'show';
        } else {
          state.current_meal += 1;
        }
      } else {
        // Show source select for next meal
        response.ui_type = 'source_select';
        response.ui_data = {
          meal_label: nextMeal.label,
          protein_target: nextEffective,
          carried_portions: nextCarried,
          available_sources: [
            { name: 'eggs', icon: '🥚' },
            { name: 'chicken', icon: '🍗' },
            { name: 'fish', icon: '🐟' },
            { name: 'mutton', icon: '🍖' }
          ]
        };
      }
    } else {
      // All meals done - build consolidation response directly
      state.step = 'consolidation';
      state.sub_step = 'awaiting_confirm';

      // Build consolidation data inline
      const productUsage = {};
      for (const m of state.meals) {
        for (const p of m.products) {
          if (!productUsage[p.product_name]) productUsage[p.product_name] = { meals: [], totalGrams: 0, category: p.category };
          productUsage[p.product_name].meals.push(m.label);
          productUsage[p.product_name].totalGrams += (p.portion_grams || 0);
        }
      }

      const consolSuggestions = [];
      for (const [pname, usage] of Object.entries(productUsage)) {
        if (usage.meals.length >= 2) {
          const prod = findProduct(pname);
          if (prod) {
            const sameCategory = products.filter(p2 => 
              (p2.category || '').toLowerCase() === (usage.category || '').toLowerCase() &&
              p2.pack_size_grams > prod.pack_size_grams
            );
            for (const bigger of sameCategory) {
              const currentPerGram = prod.price / prod.pack_size_grams;
              const biggerPerGram = bigger.price / bigger.pack_size_grams;
              if (biggerPerGram < currentPerGram && bigger.pack_size_grams >= usage.totalGrams) {
                const savings = Math.round((prod.price * usage.meals.length) - bigger.price);
                if (savings > 0) {
                  consolSuggestions.push({
                    description: 'Switch ' + pname + ' to ' + bigger.product_name + ' (' + bigger.pack_size_label + ')',
                    savings: savings
                  });
                }
              }
            }
          }
        }
      }

      // Override response with consolidation
      response = makeResponse(
        meal.label + " locked! All meals planned. Daily cost: ~₹" + state.running_price + " | Weekly estimate: ~₹" + (state.running_price * 7),
        'consolidation',
        {
          suggestions: consolSuggestions,
          total_daily_price: state.running_price,
          total_weekly_price: state.running_price * 7,
          meals_summary: state.meals.map(m => ({
            label: m.label,
            target_g: m.target_g,
            actual_g: Math.round(m.products.reduce((s, p) => s + (p.protein_g || 0), 0) * 10) / 10,
            products: m.products.map(p => p.product_name)
          }))
        }
      );
    }
  }

  // ---- MEAL CONFIRMED (transition step) ----
  else if (state.sub_step === 'meal_confirmed') {
    // User acknowledged, move forward
    if (state.current_meal < state.meals_per_day - 1) {
      state.current_meal += 1;
      state.sub_step = 'source_select';
      const meal2 = state.meals[state.current_meal];
      const carried2 = state.carried_portions[meal2.label.toLowerCase()] || [];
      const carriedP2 = carried2.reduce((s, c) => s + c.protein_g, 0);
      const effective2 = Math.max(0, meal2.target_g - carriedP2);

      response = makeResponse(
        "Let's plan " + meal2.label + "! Target: " + meal2.target_g + "g" + (carriedP2 > 0 ? " (" + Math.round(carriedP2) + "g carried, need " + effective2 + "g)" : "") + ". Choose sources:",
        'source_select',
        {
          meal_label: meal2.label,
          protein_target: effective2,
          carried_portions: carried2,
          available_sources: [
            { name: 'eggs', icon: '🥚' },
            { name: 'chicken', icon: '🍗' },
            { name: 'fish', icon: '🐟' },
            { name: 'mutton', icon: '🍖' }
          ]
        }
      );
    } else {
      state.step = 'consolidation';
      state.sub_step = 'show';
    }
  }
}

// ============================================================
// STEP: consolidation
// ============================================================
else if (state.step === 'consolidation') {
  if (state.sub_step === 'show') {
    // Check for consolidation opportunities
    const productUsage = {};
    for (const meal of state.meals) {
      for (const p of meal.products) {
        if (!productUsage[p.product_name]) productUsage[p.product_name] = { meals: [], totalGrams: 0, category: p.category };
        productUsage[p.product_name].meals.push(meal.label);
        productUsage[p.product_name].totalGrams += (p.portion_grams || 0);
      }
    }

    const suggestions = [];
    for (const [name, usage] of Object.entries(productUsage)) {
      if (usage.meals.length >= 2) {
        const prod = findProduct(name);
        if (prod) {
          // Check if a larger pack exists that could be cheaper per gram
          const sameCategory = products.filter(p => 
            (p.category || '').toLowerCase() === (usage.category || '').toLowerCase() &&
            p.pack_size_grams > prod.pack_size_grams
          );
          for (const bigger of sameCategory) {
            const currentPerGram = prod.price / prod.pack_size_grams;
            const biggerPerGram = bigger.price / bigger.pack_size_grams;
            if (biggerPerGram < currentPerGram && bigger.pack_size_grams >= usage.totalGrams) {
              const savings = Math.round((prod.price * usage.meals.length) - bigger.price);
              if (savings > 0) {
                suggestions.push({
                  description: 'Switch ' + name + ' to ' + bigger.product_name + ' (' + bigger.pack_size_label + ') - covers ' + usage.meals.join(' + '),
                  savings: savings,
                  from: name,
                  to: bigger.product_name
                });
              }
            }
          }
        }
      }
    }

    state.sub_step = 'awaiting_confirm';

    if (suggestions.length === 0) {
      response = makeResponse(
        "All meals planned! No consolidation savings found. Daily cost: ~₹" + state.running_price + " | Weekly estimate: ~₹" + (state.running_price * 7) + ". Ready to create your weekly plan and cart?",
        'consolidation',
        {
          suggestions: [],
          total_daily_price: state.running_price,
          total_weekly_price: state.running_price * 7,
          meals_summary: state.meals.map(m => ({
            label: m.label,
            target_g: m.target_g,
            actual_g: Math.round(m.products.reduce((s, p) => s + (p.protein_g || 0), 0) * 10) / 10,
            products: m.products.map(p => p.product_name)
          }))
        }
      );
    } else {
      const totalSavings = suggestions.reduce((s, sg) => s + sg.savings, 0);
      response = makeResponse(
        "Found consolidation opportunities! You could save ₹" + totalSavings + ". Apply these savings?",
        'consolidation',
        {
          suggestions: suggestions,
          total_weekly_price: state.running_price,
          potential_savings: totalSavings,
          meals_summary: state.meals.map(m => ({
            label: m.label,
            target_g: m.target_g,
            actual_g: Math.round(m.products.reduce((s, p) => s + (p.protein_g || 0), 0) * 10) / 10,
            products: m.products.map(p => p.product_name)
          }))
        }
      );
    }
  }

  else if (state.sub_step === 'awaiting_confirm') {
    // User confirmed consolidation - build weekly plan
    state.step = 'weekly_plan';
    state.sub_step = 'build';

    // Build 7-day plan (group products under each meal)
    const weeklyPlan = [];
    for (let day = 1; day <= 7; day++) {
      const dayMeals = [];
      for (const meal of state.meals) {
        const mealProducts = meal.products.map(prod => ({
          product_name: prod.product_name,
          quantity: (prod.unit === 'eggs') ? (prod.quantity + ' eggs') : (prod.portion_grams + 'g'),
          protein_g: prod.protein_g || 0
        }));
        dayMeals.push({
          meal_label: meal.label,
          products: mealProducts,
          total_protein_g: Math.round(mealProducts.reduce((s, p) => s + p.protein_g, 0) * 10) / 10
        });
      }
      weeklyPlan.push({ day: day, meals: dayMeals });
    }

    // Build cart - calculate packs needed for 7 days
    const cartMap = {};
    for (const meal of state.meals) {
      for (const prod of meal.products) {
        const fullProd = findProduct(prod.product_name);
        if (!fullProd) continue;

        const cat = (prod.category || (fullProd.category || '')).toLowerCase();
        const daysCovered = prod.days_covered || 1;

        let packsNeeded;
        if (daysCovered > 1) {
          // Pack lasts multiple days for this meal - how many packs for 7 days?
          packsNeeded = Math.ceil(7 / daysCovered);
        } else if (cat === 'eggs') {
          // Eggs: quantity is egg count, pack_size is egg count
          const labelMatch = (fullProd.pack_size_label || '').match(/(\d+)/);
          const eggCount = labelMatch ? parseInt(labelMatch[1]) : 6;
          const dailyEggs = prod.quantity || 0;
          const weeklyEggs = dailyEggs * 7;
          packsNeeded = Math.ceil(weeklyEggs / eggCount);
        } else {
          // Meat/fish: use grams
          const dailyGrams = prod.portion_grams || 0;
          const weeklyGrams = dailyGrams * 7;
          const packSize = fullProd.pack_size_grams || 450;
          packsNeeded = Math.ceil(weeklyGrams / packSize);
        }

        if (!cartMap[prod.product_name]) {
          cartMap[prod.product_name] = {
            product_name: prod.product_name,
            pack_size_label: fullProd.pack_size_label,
            packs_needed: packsNeeded,
            price_per_pack: fullProd.price,
            total_price: packsNeeded * fullProd.price,
            product_page_url: fullProd.product_page_url || '',
            image_url: fullProd.image_url || ''
          };
        } else {
          // Product used in multiple meals - add packs needed
          const existing = cartMap[prod.product_name];
          existing.packs_needed += packsNeeded;
          existing.total_price = existing.packs_needed * existing.price_per_pack;
        }
      }
    }

    const cart = Object.values(cartMap);
    const totalCartPrice = cart.reduce((s, c) => s + c.total_price, 0);

    state.weekly_plan = weeklyPlan;
    state.cart = cart;
    state.total_cart_price = totalCartPrice;

    // Also build a simple text summary for each day
    const weeklyText = weeklyPlan.map(d => {
      const dayMealsText = d.meals.map(m => {
        const prodText = m.products.map(p => p.product_name + ' (' + p.quantity + ')').join(', ');
        return m.meal_label + ': ' + prodText + ' [' + m.total_protein_g + 'g]';
      }).join(' | ');
      return 'Day ' + d.day + ': ' + dayMealsText;
    });

    response = makeResponse(
      "Here's your weekly plan and shopping cart! Total: ₹" + totalCartPrice + " for 7 days. Confirm to place your order?",
      'weekly_summary',
      {
        weekly_plan: weeklyPlan,
        weekly_text: weeklyText,
        cart: cart,
        total_cart_price: totalCartPrice,
        daily_cost: state.running_price,
        daily_protein: state.protein_target,
        distribution: state.distribution
      }
    );

    state.sub_step = 'awaiting_cart_confirm';
  }
}

// ============================================================
// STEP: weekly_plan 
// ============================================================
else if (state.step === 'weekly_plan') {
  if (state.sub_step === 'awaiting_cart_confirm') {
    const msg = userMessage;
    if (msg.includes('confirm') || msg.includes('yes') || msg.includes('ok') || msg.includes('place') || msg.includes('order')) {
      // Ask for delivery preference
      state.step = 'delivery';
      state.sub_step = 'frequency';

      response = makeResponse(
        "Great! How often would you like delivery?",
        'delivery_frequency',
        {
          frequencies: [
            { label: 'Daily (fresh every day)', value: 'daily' },
            { label: 'Every 2 days', value: 'every_2_days' },
            { label: 'Every 3 days', value: 'every_3_days' },
            { label: 'Weekly (once a week)', value: 'weekly' }
          ]
        }
      );
    } else if (msg.includes('modify') || msg.includes('change') || msg.includes('edit')) {
      // Go back to consolidation
      state.step = 'consolidation';
      state.sub_step = 'show';
      response = makeResponse("What would you like to change?", 'text_input', { prompt: "Describe what you'd like to modify:" });
    } else {
      response = makeResponse(
        "Your cart total is ₹" + state.total_cart_price + ". Would you like to confirm or modify?",
        'weekly_summary',
        {
          weekly_plan: state.weekly_plan,
          cart: state.cart,
          total_cart_price: state.total_cart_price
        }
      );
    }
  }
}

// ============================================================
// STEP: delivery
// ============================================================
else if (state.step === 'delivery') {
  if (state.sub_step === 'frequency') {
    let freq = null;
    if (selection.frequency) freq = selection.frequency;
    else {
      if (userMessage.includes('daily') || userMessage.includes('every day')) freq = 'daily';
      else if (userMessage.includes('2') || userMessage.includes('two') || userMessage.includes('alternate')) freq = 'every_2_days';
      else if (userMessage.includes('3') || userMessage.includes('three')) freq = 'every_3_days';
      else if (userMessage.includes('week') || userMessage.includes('once')) freq = 'weekly';
      else freq = null;
    }

    if (!freq) {
      response = makeResponse(
        "How often would you like delivery?",
        'delivery_frequency',
        {
          frequencies: [
            { label: 'Daily (fresh every day)', value: 'daily' },
            { label: 'Every 2 days', value: 'every_2_days' },
            { label: 'Every 3 days', value: 'every_3_days' },
            { label: 'Weekly (once a week)', value: 'weekly' }
          ]
        }
      );
    } else {
      state.delivery_frequency = freq;
      state.sub_step = 'time_slot';

      response = makeResponse(
        "Got it! What time slot works best?",
        'delivery_select',
        {
          time_slots: [
            { label: 'Morning (7-9 AM)', value: 'morning' },
            { label: 'Afternoon (12-2 PM)', value: 'afternoon' },
            { label: 'Evening (5-7 PM)', value: 'evening' }
          ]
        }
      );
    }
  }

  else if (state.sub_step === 'time_slot') {
    let slot = null;
    if (selection.time_slot) slot = selection.time_slot;
    else {
      if (userMessage.includes('morning')) slot = 'morning';
      else if (userMessage.includes('afternoon')) slot = 'afternoon';
      else if (userMessage.includes('evening')) slot = 'evening';
      else slot = 'morning';
    }

    state.delivery_slot = slot;
    state.sub_step = 'confirm_order';
    state.stage_complete = true;

    response = makeResponse(
      "Order confirmed! Delivery: " + state.delivery_frequency + ", " + slot + ". Your weekly protein plan is all set! 🎉",
      'order_confirmed',
      {
        delivery_slot: slot,
        delivery_frequency: state.delivery_frequency,
        cart: state.cart,
        total_cart_price: state.total_cart_price,
        weekly_plan: state.weekly_plan,
        daily_cost: state.running_price
      }
